import numpy as np
import cv2
import face_recognition
from flask import Flask, request, jsonify

app = Flask(__name__)

employee_photos = {
    "employee1": face_recognition.load_image_file("employee1.jpg"),
    "employee2": face_recognition.load_image_file("employee2.jpg"),
    # Add more employees as needed
}

employee_encodings = {}
for name, photo in employee_photos.items():
    encoding = face_recognition.face_encodings(photo)[0]
    employee_encodings[name] = encoding

@app.route('/recognize_faces', methods=['POST'])
def recognize_faces():
    photo = face_recognition.load_image_file(request.files['photo'])
    face_locations = face_recognition.face_locations(photo)
    face_encodings = face_recognition.face_encodings(photo, face_locations)

    results = []
    for face_encoding in face_encodings:
        face_distances = face_recognition.face_distance(list(employee_encodings.values()), face_encoding)
        probabilities = 1 - face_distances
        result = {name: prob for name, prob in zip(employee_encodings.keys(), probabilities)}
        results.append(result)

    return jsonify(results)

if __name__ == '__main__':
    app.run()